// ---------------------------------------------------------------------------
// API contract (unchanged — served by the Worker / WASM core)
// ---------------------------------------------------------------------------
type Candidate = {
  spotify_id: string;
  uri: string;
  name: string;
  artist: string;
  album: string | null;
  art: string | null;
  in_corpus?: boolean;
};

type WhyHop = {
  dist: number;
  fit: number;
  genre_jump: boolean;
  prev_genre: string;
  transition: number | null;
  context: number | null;
};

type TrackNode = {
  id: string;
  uri: string;
  name: string;
  artist: string;
  album: string | null;
  genre: string;
  spotify_url: string | null;
  fit: number | null;
  position: [number, number, number];
  // 4th principal coordinate (the variance the 3-D map discards) — present on
  // route path nodes; drives the optional "4th-dimension shadow".
  w?: number;
  kind: "path" | "requested" | "cloud" | "sample";
  snapped_to?: string | null;
  snapped_label?: string | null;
  why?: WhyHop | null;
};

type Edge = { from: string; to: string; kind: "path" | "snap" };

// single-track explorer: a track + its neighborhood in the shared layout
type EmbedResponse = {
  track: TrackNode;
  cloud: TrackNode[];
};

type RouteResponse = {
  context: string | null;
  requested_start: TrackNode;
  requested_end: TrackNode;
  path: TrackNode[];
  cloud: TrackNode[];
  edges: Edge[];
};

class ApiError extends Error {
  constructor(
    public status: number,
    message: string,
  ) {
    super(message);
  }
}

async function request<T>(path: string, init?: RequestInit): Promise<T> {
  const res = await fetch(path, init);
  if (!res.ok) {
    let message = res.statusText;
    try {
      const body = (await res.json()) as { error?: string };
      message = body.error || message;
    } catch {
      /* ignore */
    }
    throw new ApiError(res.status, message);
  }
  return res.json() as Promise<T>;
}

const post = (body: unknown): RequestInit => ({
  method: "POST",
  headers: { "content-type": "application/json" },
  body: JSON.stringify(body),
});

// bare Spotify track id from a uri/url (for compact shareable permalinks)
const idOf = (uri: string) => uri.split("?")[0].replace(/.*[:/]/, "");

// ---------------------------------------------------------------------------
// Spotify user auth — Authorization Code + PKCE, run entirely in the browser.
// Lets a listener save the journey to their own account. No client secret and
// no server session: the client id is public (served by /api/config), PKCE
// proves the exchange, and Spotify's token endpoint is CORS-enabled for public
// clients. The app's client-credentials search auth (in the Worker) is separate.
// ---------------------------------------------------------------------------
const SPOTIFY_AUTH_URL = "https://accounts.spotify.com/authorize";
const SPOTIFY_TOKEN_URL = "https://accounts.spotify.com/api/token";
const SPOTIFY_SCOPE = "playlist-modify-public playlist-modify-private";
const PKCE_VERIFIER_KEY = "pf.pkce_verifier";
const TOKEN_KEY = "pf.spotify_token";
// Persist the traced route across the OAuth redirect (which reloads the page),
// plus a flag to auto-resume the save the user clicked before signing in.
const ROUTE_KEY = "pf.route";
const PENDING_SAVE_KEY = "pf.pending_save";

const redirectUri = () => `${window.location.origin}/`;

const base64url = (bytes: ArrayBuffer): string =>
  btoa(String.fromCharCode(...new Uint8Array(bytes)))
    .replace(/\+/g, "-")
    .replace(/\//g, "_")
    .replace(/=+$/, "");

function randomVerifier(): string {
  const bytes = new Uint8Array(64);
  crypto.getRandomValues(bytes);
  return base64url(bytes.buffer);
}

async function challengeFrom(verifier: string): Promise<string> {
  const digest = await crypto.subtle.digest(
    "SHA-256",
    new TextEncoder().encode(verifier),
  );
  return base64url(digest);
}

type StoredToken = { value: string; exp: number };

function readToken(): string | null {
  try {
    const raw = sessionStorage.getItem(TOKEN_KEY);
    if (!raw) return null;
    const t = JSON.parse(raw) as StoredToken;
    return t.exp > Date.now() / 1000 + 30 ? t.value : null;
  } catch {
    return null;
  }
}

function storeToken(value: string, expiresIn: number) {
  const t: StoredToken = { value, exp: Date.now() / 1000 + expiresIn };
  sessionStorage.setItem(TOKEN_KEY, JSON.stringify(t));
}

async function beginSpotifyLogin(clientId: string) {
  const verifier = randomVerifier();
  sessionStorage.setItem(PKCE_VERIFIER_KEY, verifier);
  const params = new URLSearchParams({
    client_id: clientId,
    response_type: "code",
    redirect_uri: redirectUri(),
    scope: SPOTIFY_SCOPE,
    code_challenge_method: "S256",
    code_challenge: await challengeFrom(verifier),
  });
  window.location.assign(`${SPOTIFY_AUTH_URL}?${params}`);
}

// Exchange the ?code= we were redirected back with. Returns the access token,
// or null if there's no pending code. Throws on a real exchange failure.
async function completeSpotifyLogin(clientId: string): Promise<string | null> {
  const url = new URL(window.location.href);
  const code = url.searchParams.get("code");
  const verifier = sessionStorage.getItem(PKCE_VERIFIER_KEY);
  if (!code || !verifier) return null;
  sessionStorage.removeItem(PKCE_VERIFIER_KEY);
  // strip ?code/?state so a refresh doesn't re-trigger the exchange
  url.searchParams.delete("code");
  url.searchParams.delete("state");
  window.history.replaceState({}, "", url.pathname + url.search);
  const res = await fetch(SPOTIFY_TOKEN_URL, {
    method: "POST",
    headers: { "content-type": "application/x-www-form-urlencoded" },
    body: new URLSearchParams({
      client_id: clientId,
      grant_type: "authorization_code",
      code,
      redirect_uri: redirectUri(),
      code_verifier: verifier,
    }),
  });
  if (!res.ok)
    throw new ApiError(
      res.status,
      "Spotify sign-in failed — please try again.",
    );
  const data = (await res.json()) as {
    access_token: string;
    expires_in?: number;
  };
  storeToken(data.access_token, data.expires_in ?? 3600);
  console.log("Definitely logged in to spotify");
  return data.access_token;
}

async function spotifyApi<T>(
  token: string,
  path: string,
  init?: RequestInit,
): Promise<T> {
  const res = await fetch(`https://api.spotify.com/v1${path}`, {
    ...init,
    headers: {
      Authorization: `Bearer ${token}`,
      "content-type": "application/json",
      ...init?.headers,
    },
  });
  if (!res.ok) {
    console.log(`Spotify raw response = ${JSON.stringify(res)}`);
    let message = `Spotify request failed (${res.status})`;
    try {
      const body = (await res.json()) as { error?: { message?: string } };
      if (body.error?.message) message = body.error.message;
    } catch {
      /* ignore */
    }
    throw new ApiError(res.status, message);
  }
  return (
    res.status === 201 || res.status === 200 ? res.json() : ({} as any)
  ) as Promise<T>;
}

// Create a playlist on the signed-in account and fill it with the journey, in
// order. Returns the public Spotify URL of the new playlist.
async function createJourneyPlaylist(
  token: string,
  name: string,
  description: string,
  uris: string[],
): Promise<string> {
  const me = await spotifyApi<{ id: string }>(token, "/me");
  const playlist = await spotifyApi<{
    id: string;
    external_urls: { spotify: string };
  }>(
    token,
    `/users/${me.id}/playlists`,
    post({ name, description, public: false }),
  );
  // /tracks accepts at most 100 uris per call (paths cap at 50, so usually one)
  for (let i = 0; i < uris.length; i += 100) {
    await spotifyApi(
      token,
      `/playlists/${playlist.id}/tracks`,
      post({ uris: uris.slice(i, i + 100) }),
    );
  }
  return playlist.external_urls.spotify;
}

// Loads the public client id, completes any pending OAuth redirect, and exposes
// the current user token. clientId === null means the deploy has no Spotify
// creds, so the UI hides the playlist button.
function useSpotifyAuth() {
  const [clientId, setClientId] = useState<string | null>(null);
  const [token, setToken] = useState<string | null>(() => readToken());

  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const cfg = await request<{ spotify_client_id: string | null }>(
          "/api/config",
        );
        if (cancelled) return;
        setClientId(cfg.spotify_client_id);
        if (cfg.spotify_client_id) {
          const t = await completeSpotifyLogin(cfg.spotify_client_id);
          if (!cancelled && t) setToken(t);
        }
      } catch {
        /* config/login failures just leave the button signed-out */
      }
    })();
    return () => {
      cancelled = true;
    };
  }, []);

  const login = () => {
    if (clientId) void beginSpotifyLogin(clientId);
  };
  return { clientId, token, login };
}

const prefersReducedMotion =
  typeof window !== "undefined" &&
  window.matchMedia("(prefers-reduced-motion: reduce)").matches;

// Track a media query reactively. Drives the mobile chrome: a compact top bar
// triggers a bottom-sheet composer, and route options render inline (a popover
// anchored to a bottom-sheet field would open off-screen / get clipped).
function useMediaQuery(query: string): boolean {
  const [matches, setMatches] = useState(
    () => typeof window !== "undefined" && window.matchMedia(query).matches,
  );
  useEffect(() => {
    const mq = window.matchMedia(query);
    const onChange = () => setMatches(mq.matches);
    onChange();
    mq.addEventListener("change", onChange);
    return () => mq.removeEventListener("change", onChange);
  }, [query]);
  return matches;
}

// ---------------------------------------------------------------------------
// Genre → color. Curated ramp varying hue AND lightness so clusters stay
// distinguishable for color-vision deficiency; color is always backed by labels.
// ---------------------------------------------------------------------------
// Spectral-neon genre spectrum: high-saturation hues that pop like a
// spectrograph against near-black space. Lightness still varies across the
// ramp so clusters stay distinguishable for color-vision deficiency.
const GENRE_PALETTE = [
  "#21e6ff", // electric cyan
  "#ff3d81", // hot magenta
  "#c6ff4d", // lime
  "#a26bff", // violet
  "#ff7a18", // neon orange
  "#3dff9e", // spring green
  "#ff2bd6", // hot pink
  "#ffe23d", // neon yellow
  "#2b6bff", // electric blue
  "#ff5c5c", // coral
  "#5cffd8", // aqua
  "#b3ff2b", // chartreuse
  "#e23dff", // purple-magenta
  "#ff9d2b", // amber
];
function genreColor(genre: string): string {
  let hash = 0;
  for (let i = 0; i < genre.length; i += 1)
    hash = (hash * 31 + genre.charCodeAt(i)) >>> 0;
  return GENRE_PALETTE[hash % GENRE_PALETTE.length];
}

// smooth accel/decel for the route fly-in
const easeInOutCubic = (t: number) =>
  t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;

const SIGNAL = "#ff3d81"; // the journey — hot magenta
const COOL = "#21e6ff"; // snap / cold-start links — electric cyan

// ---------------------------------------------------------------------------
// The envelope — gather nearby tracks around the route.
// Every route comes back with a `cloud` of neighborhood tracks (the nearest
// neighbors of each stop). A "reach" control lets a listener widen an envelope
// outward from the path, pulling those tracks into the saved playlist shell by
// shell — closest first, then further and further out. The journey stays the
// spine; the neighborhood wraps around it.
// ---------------------------------------------------------------------------

// Each cloud track, ranked by its distance to the nearest route stop, closest
// first. Distances use the raw layout positions — the same space the 3-D map is
// built from — so the rings a listener widens on screen are exactly the tracks
// that get saved.
type ReachStop = { node: TrackNode; pathIndex: number; dist: number };

function analyzeCloud(route: RouteResponse): ReachStop[] {
  const pts = route.path.map((n) => new THREE.Vector3(...n.position));
  if (!pts.length) return [];
  const ranked = route.cloud.map((node) => {
    const cp = new THREE.Vector3(...node.position);
    let pathIndex = 0;
    let bestD = Infinity;
    pts.forEach((p, i) => {
      const d = cp.distanceToSquared(p);
      if (d < bestD) {
        bestD = d;
        pathIndex = i;
      }
    });
    return { node, pathIndex, dist: Math.sqrt(bestD) };
  });
  ranked.sort((a, b) => a.dist - b.dist);
  return ranked;
}

// `reach` is a continuous fog radius in [0,1]: the fraction of the
// distance-sorted neighborhood revealed around the path. 0 = route alone,
// 1 = the whole gathered neighborhood. Count = round(total * reach).
const revealedCountOf = (total: number, reach: number) =>
  Math.round(total * Math.max(0, Math.min(1, reach)));

// ---------------------------------------------------------------------------
// Space C — the composer. A route hands over its stops and a neighborhood of
// nearby candidates; the composer turns that into an explicit, editable playlist.
// `reach` (0–1) is the fog radius — how far out the neighborhood is revealed —
// and the overlays below capture the listener's edits on top of it.
// ---------------------------------------------------------------------------
type CurationRow = {
  key: string; // stable per track (its id)
  node: TrackNode;
  kind: "stop" | "nearby";
  stopIndex: number; // the stop it is, or the stop it was gathered around
  included: boolean; // rides along on save; excluded rows stay visible, dimmed
};

type Curation = {
  excluded: Set<string>; // rows toggled off
  extra: Set<string>; // nearby revealed by hand, beyond the reach radius
  order: string[] | null; // explicit drag order; null = woven default
};

const emptyCuration = (): Curation => ({
  excluded: new Set(),
  extra: new Set(),
  order: null,
});

// The neighborhood the current reach reveals from the fog (closest first). These
// become the clickable bodies in the galaxy; gathering one is a separate, explicit
// act (it joins `extra`), so reach reveals candidates rather than auto-adding them.
function revealedNearbyIds(reachCloud: ReachStop[], reach: number): Set<string> {
  const ids = new Set<string>();
  for (const r of reachCloud.slice(0, revealedCountOf(reachCloud.length, reach)))
    ids.add(r.node.id);
  return ids;
}

// Re-seat an explicit drag order against the current row set: keep the dragged
// order for rows that still exist, then splice any newly revealed rows in beside
// their stop so widening the fog doesn't scatter hand-picked tracks to the end.
function reconcileOrder(order: string[], base: CurationRow[]): CurationRow[] {
  const byKey = new Map(base.map((r) => [r.key, r]));
  const placed = new Set<string>();
  const out: CurationRow[] = [];
  for (const k of order) {
    const r = byKey.get(k);
    if (r && !placed.has(k)) {
      out.push(r);
      placed.add(k);
    }
  }
  for (const r of base) {
    if (placed.has(r.key)) continue;
    if (r.kind === "stop") {
      let idx = out.findIndex(
        (o) => o.kind === "stop" && o.stopIndex > r.stopIndex,
      );
      if (idx < 0) idx = out.length;
      out.splice(idx, 0, r);
    } else {
      let idx = -1;
      for (let i = 0; i < out.length; i += 1)
        if (out[i].stopIndex === r.stopIndex) idx = i;
      if (idx < 0) out.push(r);
      else out.splice(idx + 1, 0, r);
    }
    placed.add(r.key);
  }
  return out;
}

// The playlist rows: the route's stops plus the nearby tracks gathered by hand
// (curation.extra), each woven in after the stop it sits closest to. Reach no
// longer adds rows — it only reveals candidates in the galaxy; gathering is the
// explicit click. Stops can be dropped (excluded) but stay as restorable rows.
function buildCuration(
  route: RouteResponse,
  reachCloud: ReachStop[],
  _reach: number,
  cur: Curation,
): CurationRow[] {
  const gathered = reachCloud.filter((r) => cur.extra.has(r.node.id));
  const byStop = new Map<number, ReachStop[]>();
  for (const r of gathered) {
    const arr = byStop.get(r.pathIndex);
    if (arr) arr.push(r);
    else byStop.set(r.pathIndex, [r]);
  }
  const base: CurationRow[] = [];
  route.path.forEach((n, i) => {
    base.push({
      key: n.id,
      node: n,
      kind: "stop",
      stopIndex: i,
      included: !cur.excluded.has(n.id),
    });
    for (const r of (byStop.get(i) ?? []).sort((a, b) => a.dist - b.dist))
      base.push({
        key: r.node.id,
        node: r.node,
        kind: "nearby",
        stopIndex: i,
        included: true,
      });
  });
  return cur.order ? reconcileOrder(cur.order, base) : base;
}

// Final Spotify uri list: the included rows in order, with the listener's actual
// picks (which may have been snapped) bookending it. De-duped, real tracks only.
function curationToUris(route: RouteResponse, rows: CurationRow[]): string[] {
  const uris: string[] = [];
  const included = rows.filter((r) => r.included).map((r) => r.node.uri);
  const startUri = route.requested_start.uri;
  if (startUri && startUri !== included[0]) uris.push(startUri);
  uris.push(...included);
  const endUri = route.requested_end.uri;
  if (endUri && endUri !== included[included.length - 1]) uris.push(endUri);
  const seen = new Set<string>();
  return uris.filter(
    (u) => /^spotify:track:/.test(u) && !seen.has(u) && (seen.add(u), true),
  );
}

